#include <bits/stdc++.h>
using namespace std;
string a[102][102],b;
int x[8]{-1,-1,-1,0,0,1,1,1},y[8]{-1,0,1,-1,1,-1,0,1};
int main(){
	int n,m;
	cin>>n>>m;
	for(int i=1;i<=n;i++){
		cin>>b;
		for(int j=1;j<=m;j++){
			a[i][j]=b[j-1];
		}
	}
	for(int i=1;i<=n;i++){
		for(int j=1;j<=m;j++){
			if(a[i][j]=="*"){
				cout<<"*";
			}
			else{
				int s=0;
				for(int k=0;k<8;k++){
					int xx=i+x[k];
					int yy=j+y[k];
					if(a[xx][yy]=="*"){
						s++;
					}
				}
				cout<<s;
			}
		}
		cout<<endl;
	}
}
